function [fx] =My2DGauss(pixelWidth ,m, sd)% function fx=MyGauss(x,m,a)% creates a 2 dimensional unit Gaussian function, height of 1% useful for creating Gaussian envelopes for Gabor stimuli\%% pixel width specifies the grid size for the resulting 2D matrix,% which comes back as pixelWidth + 1, adding the zero pointx = [-2*pi:4*pi/pixelWidth:2*pi];y=(x-m)/(sd*sqrt(2*pi));fx=exp(-pi*y.^2);fx = fx'*fx;